mapper.select:
select id, code, name, type_category_id as typeCategoryId, login_url as loginUrl, realm.register_enabled as registerEnabled, sso_enabled as ssoEnabled, password_policy as passwordPolicy, mfa_policy as mfaPolicy, unique_policy as uniquePolicy, status, description, create_time, update_time from realm
and `name` like concat('%', #{realmPageRequest.name}, '%')
and `code` = #{realmPageRequest.code}
and `status` = #{realmPageRequest.status}
order by update_time desc, create_time desc
